const query = $input.first().json.query || {};
const slug = query.slug || query.barberia_slug || null;
const idRaw = query.barberia_id || query.id_barberia || null;
const barberia_id = idRaw ? Number(idRaw) : null;
return [{ json: { slug, barberia_id } }];

const data = $input.first().json.result || {};
const barberia = data.barberia || {};
const servicios = data.servicios || [];
const barberos = data.barberos || [];
const horarios = data.horarios || [];
const clientes = data.clientes || [];
const reservas = data.reservas || [];

const firstText = (...values) => values.map(v => (v ?? '').toString().trim()).find(Boolean) || '';
const firstNumber = (...values) => {
  for (const value of values) {
    const n = Number(value);
    if (Number.isFinite(n) && n > 0) return n;
  }
  return null;
};

const mappedServices = servicios.map(s => ({
  id: s.id,
  barberia_id: s.barberia_id,
  nombre: s.nombre,
  duracion_min: s.duracion_min,
  precio: s.precio,
  activo: s.activo,
  imagen_url: s.imagen_url
}));

const mappedBarbers = barberos.map(b => ({
  id: b.id,
  barberia_id: b.barberia_id,
  nombre: b.nombre,
  activo: b.activo,
  usuario_id: b.usuario_id,
  foto_url: b.foto_url
}));

const mappedHours = horarios.map(h => ({
  id: h.id,
  barberia_id: h.barberia_id,
  dia_semana: h.dia_semana,
  activo: h.activo,
  hora_abre: h.hora_abre,
  hora_cierra: h.hora_cierra
}));

const mappedClients = clientes.map(c => ({
  id: c.id,
  barberia_id: firstNumber(c.barberia_id),
  nombre: firstText(c.nombre),
  telefono: firstText(c.telefono),
  created_at: c.created_at
}));

const mappedReservations = reservas.map(c => ({
  id: c.id,
  barberia_id: firstNumber(c.dashboard_barberia_id, c.barberia_id),
  barbero_id: firstNumber(c.dashboard_barbero_id, c.barbero_id),
  id_barbero: firstNumber(c.dashboard_barbero_id, c.barbero_id),
  servicio_id: firstNumber(c.dashboard_servicio_id, c.servicio_id),
  id_servicio: firstNumber(c.dashboard_servicio_id, c.servicio_id),
  cliente_id: firstNumber(c.dashboard_cliente_id, c.cliente_id),
  cliente_nombre: firstText(c.dashboard_cliente_nombre, c.cliente_nombre),
  cliente_tel: firstText(c.dashboard_cliente_tel, c.cliente_tel),
  fecha: firstText(c.fecha),
  hora_inicio: firstText(c.hora_inicio),
  hora_fin: firstText(c.hora_fin),
  servicio_nombre: firstText(c.servicio_nombre),
  barbero_nombre: firstText(c.barbero_nombre),
  estado: firstText(c.estado) || 'confirmada',
  total: Number(c.total || c.precio || 0),
  pago_id: c.pago_id ? Number(c.pago_id) : null,
  total_pagado: c.total_pagado ? Number(c.total_pagado) : null,
  metodo_pago: c.metodo_pago || null,
  pagado_en: c.pagado_en || null,
  created_at: c.created_at
}));

const now = new Date();
const todayDay = now.getDate();
const todayMonth = now.getMonth();
const todayYear = now.getFullYear();
const todayDateString = todayYear + "-" + String(todayMonth + 1).padStart(2, "0") + "-" + String(todayDay).padStart(2, "0");

const todayCitas = mappedReservations.filter(r => String(r.fecha || '').startsWith(todayDateString));
const monthlyIncome = mappedReservations.reduce((sum, r) => sum + Number(r.total || 0), 0);

const response = {
  ok: true,
  identity: {
    barberia_id: barberia.id || null,
    slug: barberia.slug || null
  },
  seed: {
    id: barberia.id,
    nombre: barberia.nombre,
    slug: barberia.slug,
    services: mappedServices,
    barbers: mappedBarbers,
    hours: mappedHours,
    clients: mappedClients,
    appointments: mappedReservations
  },
  merged: {
    biz_name: barberia.nombre,
    biz_slug: barberia.slug,
    services: mappedServices,
    barbers: mappedBarbers,
    hours: mappedHours,
    clients: mappedClients,
    appointments: mappedReservations
  },
  barberia: barberia,
  reservas: mappedReservations,
  clientes: mappedClients,
  metricas: {
    ingresos_mensuales: monthlyIncome,
    citas_hoy: todayCitas.length,
    nuevos_clientes: mappedClients.length
  },
  barberos: mappedBarbers,
  servicios: mappedServices
};

return [{ json: response }];

